 namespace WPAICG\AutoGPT\Cron\EventProcessor\Helpers; if (!defined('ABSPATH')) { exit; } function log_cron_error_logic(string $message, ?int $itemId = null): void { $log_message = "AIPKit Cron Processor Error: {$message}"; if ($itemId !== null) { $log_message .= " (Queue Item ID: {$itemId})"; } } 